begin;
create extension if not exists pgtap;
create schema if not exists tests;
insert into auth.users (id, aud, role, email, encrypted_password, email_confirmed_at) values ('00000000-0000-0000-0000-000000000081', 'authenticated', 'authenticated', 'communications-owner@example.test', 'local-test-only', timezone('utc', now())) on conflict (id) do nothing;
insert into public.organizations (id, name, display_name, slug) values ('b1000000-0000-0000-0000-000000000001', 'Communications Organization', 'Communications Organization', 'communications-organization');
insert into public.clinics (id, organization_id, name, slug) values ('b2000000-0000-0000-0000-000000000001', 'b1000000-0000-0000-0000-000000000001', 'Communications Clinic', 'communications-clinic');
insert into public.locations (id, organization_id, clinic_id, name) values ('b3000000-0000-0000-0000-000000000001', 'b1000000-0000-0000-0000-000000000001', 'b2000000-0000-0000-0000-000000000001', 'Communications Location');
insert into public.organization_memberships (id, organization_id, profile_id, status, accepted_at) values ('b4000000-0000-0000-0000-000000000001', 'b1000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000081', 'active', timezone('utc', now()));
insert into public.membership_roles (organization_id, membership_id, role_id) select 'b1000000-0000-0000-0000-000000000001', 'b4000000-0000-0000-0000-000000000001', id from public.roles where key = 'organization.owner';
select plan(16);
set local role anon;
select throws_ok($$select public.create_notification('b1000000-0000-0000-0000-000000000001', gen_random_uuid(), null, 'internal', null, 'Denied')$$, 'P0001', 'Permission denied', 'anonymous notification creation is denied');
set local role authenticated;
select set_config('request.jwt.claim.sub', '00000000-0000-0000-0000-000000000081', true);
create temp table communication_patient on commit drop as select * from public.create_patient('b1000000-0000-0000-0000-000000000001', 'CM-001', 'Communication', null, 'Patient', null, null, '1980-01-01', 'undisclosed', null, null, 'undisclosed', null, 'en', false, null, null, null, 'active', null, null);
select lives_ok($$select public.update_preferences((select patient_id from communication_patient), true, false, false, true, 'en-CA', '{}'::jsonb)$$, 'patient preferences are updated through an RPC');
select is((select email_enabled from public.patient_notification_preferences limit 1), true, 'email preference is stored');
select lives_ok($$select public.update_notification_settings(60, '{}'::jsonb, null, 'America/Edmonton')$$, 'organization settings are updated through an RPC');
select lives_ok($$select public.update_templates('b1000000-0000-0000-0000-000000000001', null, 'appointment.reminder', 'email', 'Reminder', 'Appointment reminder', '{}'::jsonb, 'en-CA')$$, 'template version one is created');
select is((select version from public.notification_templates limit 1), 1, 'first template version is one');
create temp table communication_template on commit drop as select id from public.notification_templates limit 1;
select lives_ok($$select public.update_templates('b1000000-0000-0000-0000-000000000001', (select id from communication_template), 'appointment.reminder', 'email', 'Reminder v2', 'Updated reminder', '{}'::jsonb, 'en-CA')$$, 'template update creates a new version');
select is((select max(version) from public.notification_templates), 2, 'template version increments');
select is((select count(*)::integer from public.notification_templates where status = 'active'), 1, 'only latest template is active');
select throws_ok($$insert into public.notification_queue(organization_id, patient_id, channel, recipient_address, body) values ('b1000000-0000-0000-0000-000000000001', (select patient_id from communication_patient), 'internal', 'internal', 'Denied')$$, '42501', null, 'direct queue writes are denied');
create temp table communication_queue on commit drop as select public.create_notification('b1000000-0000-0000-0000-000000000001', (select patient_id from communication_patient), null, 'internal', 'Test', 'Mock body');
select is((select status from public.notification_queue limit 1), 'pending', 'notification starts pending');
select lives_ok($$select public.send_mock_notification((select create_notification from communication_queue))$$, 'mock delivery succeeds without a provider');
select is((select status from public.notification_queue limit 1), 'sent', 'mock delivery marks queue sent');
select is((select provider from public.notification_deliveries limit 1), 'mock', 'delivery provider is mock');
select is((select count(*)::integer from public.notification_events), 1, 'delivery creates an event');
set local role postgres;
select ok((select count(*) from public.audit_events where organization_id = 'b1000000-0000-0000-0000-000000000001' and action like 'notification.%') >= 6, 'communication mutations are audited');
select * from finish();
rollback;
